changeSet.sql:
create table location
(
    id            bigint auto_increment
    primary key,
    city          varchar(255) null,
    country       varchar(255) null,
    location_code varchar(255) null,
    name          varchar(255) null
);


INSERT INTO location (id, city, country, location_code, name)
    VALUES (3, 'İstanbul', 'Turkey', '', 'Taksim Square');
INSERT INTO location (id, city, country, location_code, name)
    VALUES (4, 'İstanbul', 'Turkey', 'IST', 'İstanbul Airport');
INSERT INTO location (id, city, country, location_code, name)
    VALUES (5, 'İstanbul', 'Turkey', 'SAW', 'İstanbul Sabiha Gökçen Airport');
INSERT INTO location (id, city, country, location_code, name)
    VALUES (6, 'London', 'England', 'LHR', 'London Heathrow Airport');
INSERT INTO location (id, city, country, location_code, name)
    VALUES (7, 'London', 'England', '', 'Webley Stadium');

create table transportation
(
    id             bigint auto_increment
    primary key,
    type           varchar(255) null,
    from_id        bigint       null,
    to_id          bigint       null,
    operating_days tinyint      not null,
    constraint FK_transportation_to_location
        foreign key (to_id) references location (id),
    constraint FK_transportation_from_location
        foreign key (from_id) references location (id)
);

INSERT INTO transportation (id, type, from_id, to_id, operating_days) VALUES (2, 'UBER', 3, 4, 127);
INSERT INTO transportation (id, type, from_id, to_id, operating_days) VALUES (3, 'SUBWAY', 3, 4, 127);
